// Calculate cost basis, proceeds, gain/loss using FIFO method
// Format as IRS Form 8949 rows
const trades = $('Get All Trades').all();
const positions = $('Get Open Positions').all();

// Build FIFO lots per token
const lots = {}; // tokenId -> [{price, size, date}]
const taxRows = [];
let totalGains = 0;
let totalLosses = 0;
let totalTrades = 0;
const ONE_YEAR_MS = 365.25 * 24 * 60 * 60 * 1000;

// Sort trades by timestamp ascending for FIFO
const sortedTrades = trades
  .map(t => t.json)
  .sort((a, b) => new Date(a.timestamp || a.createdAt || 0).getTime() - new Date(b.timestamp || b.createdAt || 0).getTime());

for (const trade of sortedTrades) {
  const tokenId = trade.tokenId || trade.asset || 'unknown';
  const side = (trade.side || trade.type || '').toUpperCase();
  const price = Number(trade.price || 0);
  const size = Number(trade.size || trade.amount || 0);
  const tradeDate = new Date(trade.timestamp || trade.createdAt || 0);
  const market = trade.market || trade.question || trade.conditionId || 'Polymarket Position';

  if (!lots[tokenId]) lots[tokenId] = [];

  if (side === 'BUY') {
    // Add to FIFO queue
    lots[tokenId].push({ price, size, date: tradeDate });
  } else if (side === 'SELL') {
    // Match against oldest lots (FIFO)
    let remaining = size;
    while (remaining > 0 && lots[tokenId].length > 0) {
      const lot = lots[tokenId][0];
      const matched = Math.min(remaining, lot.size);

      const costBasis = matched * lot.price;
      const proceeds = matched * price;
      const gainLoss = proceeds - costBasis;
      const holdingMs = tradeDate.getTime() - lot.date.getTime();
      const term = holdingMs > ONE_YEAR_MS ? 'Long-term' : 'Short-term';

      totalTrades++;
      if (gainLoss >= 0) totalGains += gainLoss;
      else totalLosses += Math.abs(gainLoss);

      taxRows.push({
        json: {
          Description: `${market} (${matched.toFixed(2)} shares)`,
          'Date Acquired': lot.date.toISOString().split('T')[0],
          'Date Sold': tradeDate.toISOString().split('T')[0],
          Proceeds: '$' + proceeds.toFixed(2),
          'Cost Basis': '$' + costBasis.toFixed(2),
          'Gain/Loss': (gainLoss >= 0 ? '+$' : '-$') + Math.abs(gainLoss).toFixed(2),
          Term: term
        }
      });

      lot.size -= matched;
      remaining -= matched;
      if (lot.size <= 0) lots[tokenId].shift();
    }
  }
}

// Add summary row
taxRows.push({
  json: {
    Description: '--- SUMMARY ---',
    'Date Acquired': '',
    'Date Sold': '',
    Proceeds: '',
    'Cost Basis': '',
    'Gain/Loss': '',
    Term: ''
  }
});

taxRows.push({
  json: {
    Description: `Total: ${totalTrades} dispositions`,
    'Date Acquired': '',
    'Date Sold': '',
    Proceeds: '',
    'Cost Basis': 'Total Gains:',
    'Gain/Loss': '+$' + totalGains.toFixed(2),
    Term: ''
  }
});

taxRows.push({
  json: {
    Description: '',
    'Date Acquired': '',
    'Date Sold': '',
    Proceeds: '',
    'Cost Basis': 'Total Losses:',
    'Gain/Loss': '-$' + totalLosses.toFixed(2),
    Term: ''
  }
});

taxRows.push({
  json: {
    Description: '',
    'Date Acquired': '',
    'Date Sold': '',
    Proceeds: '',
    'Cost Basis': 'Net:',
    'Gain/Loss': (totalGains - totalLosses >= 0 ? '+$' : '-$') + Math.abs(totalGains - totalLosses).toFixed(2),
    Term: '',
    _totalTrades: totalTrades,
    _totalGains: totalGains.toFixed(2),
    _totalLosses: totalLosses.toFixed(2)
  }
});

return taxRows;

